const alert = $input.item.json;
const body = alert.body || alert;
const alertData = body.alert || body;

const rule = alertData.rule || {};
const agent = alertData.agent || {};
const data = alertData.data || {};

const severityLevel = parseInt(rule.level) || 0;
let priority = 1;
if (severityLevel >= 12) priority = 3;
else if (severityLevel >= 7) priority = 2;

return {
  json: {
    alertData: {
      rule_id: rule.id,
      rule_description: rule.description,
      severity: severityLevel,
      priority: priority,
      source_ip: data.srcip || 'N/A',
      dest_ip: data.dstip || 'N/A',
      hostname: agent.name || 'N/A',
      agent_id: agent.id || 'N/A',
      full_log: alertData.full_log || '',
      timestamp: alertData.timestamp || new Date().toISOString(),
      mitre_tactics: (rule.mitre?.tactic || []).join(', '),
      mitre_ids: (rule.mitre?.id || []).join(', '),
      groups: (rule.groups || []).join(', ')
    },
    prompt: ''
  }
};

const data = $input.item.json;
let analysis = {
  threat_intent: 'No AI response',
  blast_radius: { affected_systems: [], scope: 'unknown', data_at_risk: [] },
  mitre_attack: { primary_technique: 'N/A', techniques: [], tactics: [] },
  remediation_options: [],
  recommended_action: 'None',
  confidence_score: 0,
  inconclusive: true
};

try {
  if (data.candidates && data.candidates[0]?.content?.parts?.[0]?.text) {
    const text = data.candidates[0].content.parts[0].text;
    const match = text.match(/\{[\s\S]*\}/);
    if (match) analysis = JSON.parse(match[0]);
  }
} catch (e) {
  analysis.threat_intent = 'Error parsing AI response: ' + e.message;
}

return { json: analysis };

const analysis = $input.item.json;
const alertData = $('Parse Alert').item.json.alertData;

const remediationHtml = analysis.remediation_options.map((r, i) => 
  '<li><strong>' + (i + 1) + '. ' + r.action + '</strong><br>Description: ' + r.description + '<br>Impact: ' + r.impact + '<br>Confidence: ' + ((r.confidence || 0) * 100).toFixed(0) + '%</li>'
).join('');

const blastRadiusHtml = '<p><strong>Affected Systems:</strong> ' + (analysis.blast_radius.affected_systems.join(', ') || 'None identified') + '</p><p><strong>Scope:</strong> ' + analysis.blast_radius.scope + '</p><p><strong>Data at Risk:</strong> ' + (analysis.blast_radius.data_at_risk.join(', ') || 'None identified') + '</p>';

const mitreHtml = '<p><strong>Primary Technique:</strong> ' + analysis.mitre_attack.primary_technique + '</p><p><strong>Tactics:</strong> ' + (analysis.mitre_attack.tactics.join(', ') || 'N/A') + '</p><p><strong>Techniques:</strong> ' + (analysis.mitre_attack.techniques.join(', ') || 'N/A') + '</p>';

const body = '<h2>Deep Threat Analysis Report</h2><h3>Alert Details</h3><p><strong>Rule:</strong> ' + alertData.rule_description + '</p><p><strong>Severity:</strong> ' + alertData.severity + '/15</p><p><strong>Host:</strong> ' + alertData.hostname + '</p><p><strong>Source IP:</strong> ' + alertData.source_ip + '</p><p><strong>Destination IP:</strong> ' + alertData.dest_ip + '</p><h3>Threat Intent</h3><p>' + analysis.threat_intent + '</p><h3>Blast Radius Assessment</h3>' + blastRadiusHtml + '<h3>MITRE ATT&CK Mapping</h3>' + mitreHtml + '<h3>Remediation Options</h3><ol>' + (remediationHtml || '<li>No options generated</li>') + '</ol><h3>Recommended Action</h3><p><strong>' + analysis.recommended_action + '</strong></p><h3>Analysis Confidence</h3><p>Confidence Score: ' + ((analysis.confidence_score || 0) * 100).toFixed(0) + '%</p><p>Status: ' + (analysis.inconclusive ? 'INCONCLUSIVE - Requires manual forensic investigation' : 'Analysis Complete') + '</p><hr><p><small>Generated by SOC AI Automation - Agent 2: Threat Responder</small></p>';

return { json: { body } };
